import Link from 'next/link';
import styles from './page.module.scss';

type Activity = {
  href: string;
  title: string;
  description: string;
  icon: string;
  tag: string;
  tagClass: keyof Pick<typeof styles, 'tagGreen' | 'tagBlue' | 'tagAmber' | 'tagMuted'>;
  disabled?: boolean;
};

const activities: Activity[] = [
  {
    href: '/vocabulary',
    title: 'Vocabulary',
    description:
      'Search and organize your words, track new vs known, and flip through flashcards to memorize faster.',
    icon: '📚',
    tag: 'Words',
    tagClass: 'tagGreen',
  },
  {
    href: '/quiz',
    title: 'Quiz',
    description:
      'Multiple-choice and fill-in questions on grammar and vocabulary with explanations after each answer.',
    icon: '🎯',
    tag: 'Grammar',
    tagClass: 'tagBlue',
  },
  {
    href: '#',
    title: 'Speaking',
    description:
      'Guided speaking prompts and pronunciation practice — we are preparing this mode for your level.',
    icon: '🎙️',
    tag: 'Soon',
    tagClass: 'tagMuted',
    disabled: true,
  },
];

export default function PracticePage() {
  return (
    <div className={`${styles.page} container container--page`}>
      <header className={styles.pageHeader}>
        <h1 className={styles.pageTitle}>Practice</h1>
        <p className={styles.pageSub}>
          Pick an activity: build vocabulary like in the Vocabulary area, or run drills like in the Quiz — all from one
          place.
        </p>
      </header>

      <div className={styles.grid}>
        {activities.map((activity) => {
          const tagStyle = styles[activity.tagClass];
          const body = (
            <>
              <div className={styles.cardIcon} aria-hidden>
                {activity.icon}
              </div>
              <h2 className={styles.cardTitle}>{activity.title}</h2>
              <p className={styles.cardDesc}>{activity.description}</p>
              <div className={styles.cardFooter}>
                <span className={`${styles.tag} ${tagStyle}`}>{activity.tag}</span>
                <span className={styles.cta}>{activity.disabled ? 'Coming soon' : 'Open →'}</span>
              </div>
            </>
          );

          if (activity.disabled) {
            return (
              <article key={activity.title} className={`${styles.card} ${styles.cardDisabled}`}>
                {body}
              </article>
            );
          }

          return (
            <Link key={activity.href} href={activity.href} className={styles.card}>
              {body}
            </Link>
          );
        })}
      </div>
    </div>
  );
}
